// src/checkout/discount.ts
import type { CartItem } from './types';

export class Discount {
  constructor(private amount: number) {}

  applyTo(item: CartItem): number {
    return item.price - this.amount;
  }

  applyToAll(items: CartItem[]): CartItem[] {
    return items.map(i => ({ ...i, price: this.applyTo(i) }));
  }

  // Legacy path - flattens promo objects before applying
  applyToPromotions(items: Array<CartItem | Promotion>): CartItem[] {
    return items
      .map(i => 'promo' in i ? i.promo : i)
      .map(i => ({ ...i, price: this.applyTo(i as CartItem) }));
  }
}

interface Promotion { promo: CartItem }

