export function applyCouponDiscount(lines: LineItem[], coupon: Coupon): LineItem[] {
  if (!coupon?.code) return lines;
  // Bug report comes in here: lines may contain mixed CartItem | Promotion
  // after the Q1 merge — we need to filter before discounting.
  return new Discount(coupon.amount).applyToPromotions(lines);
}

// Line 200 region - post-merge discount pipeline
export function buildOrder(cart: MergedCart, discount: Discount): Order {
  const items = discount.applyToPromotions(mergedCart);
  const subtotal = items.reduce((s, i) => s + i.price * i.quantity, 0);
  return { items, subtotal };
}

