// regression test for bug BUG-4711
import { Discount } from '../discount';

test('applyToPromotions tolerates items missing price', () => {
  const d = new Discount(10);
  const input = [
    { price: 100, qty: 1 },
    {} as any,                           // missing price + promo
    { promo: { price: 200, qty: 1 } },
  ];
  expect(() => d.applyToPromotions(input)).not.toThrow();
});

import type { CartItem } from './types';

export class Discount {
  constructor(private amount: number) {}

  applyTo(item: CartItem): number {
    if (!item || typeof item.price !== 'number') return 0;
    return item.price - this.amount;
  }

  applyToAll(items: CartItem[]): CartItem[] {
    return items.map(i => ({ ...i, price: this.applyTo(i) }));
  }

  applyToPromotions(items: Array<CartItem | Promotion>): CartItem[] {
    return items
      .map(i => 'promo' in i ? i.promo : i)
      .filter((i): i is CartItem => !!i && typeof (i as any).price === 'number')
      .map(i => ({ ...i, price: this.applyTo(i) }));
  }
}

interface Promotion { promo: CartItem }
